import heapq


class TaskManager:
    def __init__(self, tasks):
        self.priority = {}
        self.owner = {}
        self.heap = []
        for userId, taskId, prio in tasks:
            self.owner[taskId] = userId
            self.priority[taskId] = prio
            heapq.heappush(self.heap, (-prio, -taskId, taskId))

    def add(self, userId, taskId, priority):
        self.owner[taskId] = userId
        self.priority[taskId] = priority
        heapq.heappush(self.heap, (-priority, -taskId, taskId))

    def edit(self, taskId, newPriority):
        self.priority[taskId] = newPriority
        heapq.heappush(self.heap, (-newPriority, -taskId, taskId))

    def rmv(self, taskId):
        self.priority.pop(taskId, None)
        self.owner.pop(taskId, None)

    def execTop(self):
        while self.heap:
            negp, _negt, taskId = heapq.heappop(self.heap)
            if taskId in self.priority and self.priority[taskId] == -negp:
                userId = self.owner[taskId]
                del self.priority[taskId]
                del self.owner[taskId]
                return userId
        return -1

