class TaskManager {
    constructor(tasks) {
        this.priority = new Map();
        this.owner = new Map();
        this.heap = [];
        for (const [userId, taskId, prio] of tasks) {
            this.owner.set(taskId, userId);
            this.priority.set(taskId, prio);
            this._push(prio, taskId);
        }
    }
    _better(a, b) {
        if (a[0] !== b[0]) return a[0] > b[0];
        return a[1] > b[1];
    }
    _push(priority, taskId) {
        const heap = this.heap;
        heap.push([priority, taskId]);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (this._better(heap[i], heap[p])) {
                [heap[i], heap[p]] = [heap[p], heap[i]];
                i = p;
            } else break;
        }
    }
    _pop() {
        const heap = this.heap;
        const top = heap[0];
        const last = heap.pop();
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            while (true) {
                let best = i;
                const l = 2 * i + 1;
                const r = 2 * i + 2;
                if (l < heap.length && this._better(heap[l], heap[best])) best = l;
                if (r < heap.length && this._better(heap[r], heap[best])) best = r;
                if (best === i) break;
                [heap[i], heap[best]] = [heap[best], heap[i]];
                i = best;
            }
        }
        return top;
    }
    add(userId, taskId, priority) {
        this.owner.set(taskId, userId);
        this.priority.set(taskId, priority);
        this._push(priority, taskId);
    }
    edit(taskId, newPriority) {
        this.priority.set(taskId, newPriority);
        this._push(newPriority, taskId);
    }
    rmv(taskId) {
        this.priority.delete(taskId);
        this.owner.delete(taskId);
    }
    execTop() {
        while (this.heap.length > 0) {
            const [p, taskId] = this._pop();
            if (this.priority.has(taskId) && this.priority.get(taskId) === p) {
                const userId = this.owner.get(taskId);
                this.priority.delete(taskId);
                this.owner.delete(taskId);
                return userId;
            }
        }
        return -1;
    }
}
